import 'package:flutter/material.dart';import '../../design_system/app_colors.dart';import '../../design_system/app_spacing.dart';import '../../design_system/app_typography.dart';import '../../design_system/ds_buttons.dart';import '../../design_system/ds_card.dart';import '../../design_system/ds_input_field.dart';class ReportsExportScreen extends StatefulWidget {  const ReportsExportScreen({super.key});  @override  State<ReportsExportScreen> createState() => _ReportsExportScreenState();}@overrideclass _ReportsExportScreenState extends State<ReportsExportScreen> {  String _selectedDateRange = 'Last Month';  List<String> _selectedCategories = [];  List<String> _selectedMerchants = [];  bool _includeReceipts = false;  String _exportFormat = 'PDF';  @override  Widget build(BuildContext context) {    return Scaffold(      backgroundColor: AppColors.background,      appBar: AppBar(        title: Text('Reports & Export', style: AppTypography.h2),      ),      body: ListView(        padding: AppSpacing.screenPadding,        children: [          _buildDateRangePicker(),          SizedBox(height: AppSpacing.paddingMedium),          _buildFilterOption('Select Categories', _selectedCategories, () {            ScaffoldMessenger.of(context).showSnackBar(              const SnackBar(content: Text('Category filter coming soon!')),            );          }),          SizedBox(height: AppSpacing.paddingMedium),          _buildFilterOption('Select Merchants', _selectedMerchants, () {            ScaffoldMessenger.of(context).showSnackBar(              const SnackBar(content: Text('Merchant filter coming soon!')),            );          }),          SizedBox(height: AppSpacing.paddingMedium),          _buildToggleOption(            'Include Receipts',            _includeReceipts,            (value) => setState(() => _includeReceipts = value),          ),          SizedBox(height: AppSpacing.paddingMedium),          _buildExportFormatDropdown(),          SizedBox(height: AppSpacing.paddingLarge),          DsPrimaryButton(            text: 'Generate Report',            onPressed: () {              ScaffoldMessenger.of(context).showSnackBar(                SnackBar(content: Text('Generating $_exportFormat report for $_selectedDateRange...')),              );            },          ),          SizedBox(height: AppSpacing.paddingLarge),          Text('Recent Reports', style: AppTypography.h2),          SizedBox(height: AppSpacing.paddingMedium),          DsCard(            child: Column(              crossAxisAlignment: CrossAxisAlignment.start,              children: [                Text('No recent reports.',                  style: AppTypography.body.copyWith(color: AppColors.textSecondary)),                // TODO: List of recent reports              ],            ),          ),        ],      ),    );  }  Widget _buildDateRangePicker() {    return DsInputField(      labelText: 'Date Range',      readOnly: true,      controller: TextEditingController(text: _selectedDateRange),      onTap: () {        // TODO: Implement a custom date range picker modal        ScaffoldMessenger.of(context).showSnackBar(          const SnackBar(content: Text('Custom date range picker coming soon!')),        );      },      suffixIcon: Icon(Icons.calendar_today_outlined,          color: AppColors.textSecondary, size: AppSpacing.iconSizeMedium),    );  }  Widget _buildFilterOption(      String title, List<String> selectedItems, VoidCallback onTap) {    return DsInputField(      labelText: title,      readOnly: true,      controller: TextEditingController(          text: selectedItems.isEmpty ? 'All' : selectedItems.join(', ')),      onTap: onTap,      suffixIcon: Icon(Icons.arrow_forward_ios,          color: AppColors.textSecondary, size: AppSpacing.iconSizeMedium / 1.5),    );  }  Widget _buildToggleOption(String title, bool value, ValueChanged<bool> onChanged) {    return Row(      mainAxisAlignment: MainAxisAlignment.spaceBetween,      children: [        Text(title, style: AppTypography.body),        Switch(          value: value,          onChanged: onChanged,          activeColor: AppColors.primary,          inactiveTrackColor: AppColors.inputBorder,        ),      ],    );  }  Widget _buildExportFormatDropdown() {    return Column(      crossAxisAlignment: CrossAxisAlignment.start,      children: [        Padding(          padding: const EdgeInsets.only(bottom: AppSpacing.paddingSmall / 2),          child: Text(            'Export Format',            style: AppTypography.body.copyWith(color: AppColors.textSecondary),          ),        ),        Container(          decoration: BoxDecoration(            color: AppColors.surface,            borderRadius: BorderRadius.circular(AppSpacing.borderRadiusSmall),            border: Border.all(color: AppColors.inputBorder),          ),          child: DropdownButtonFormField<String>(            value: _exportFormat,            decoration: InputDecoration(              border: InputBorder.none,              contentPadding: AppSpacing.inputPadding,              isDense: true,            ),            dropdownColor: AppColors.surface,            style: AppTypography.inputField,            iconEnabledColor: AppColors.textSecondary,            onChanged: (String? newValue) {              if (newValue != null) {                setState(() {                  _exportFormat = newValue;                });              }            },            items: <String>['CSV', 'PDF']                .map<DropdownMenuItem<String>>((String value) {              return DropdownMenuItem<String>(                value: value,                child: Text(value, style: AppTypography.inputField),              );            }).toList(),          ),        ),      ],    );  }}